import { ICloudbase } from '@cloudbase/types'
import { ICloudbaseComponent } from '@cloudbase/types/component'
import { CloudBaseInstance, generateMySQLClient, IMySqlOptions } from '@cloudbase/wx-cloud-client-sdk'

declare const cloudbase: ICloudbase

function getEntity(cloudbase: any & CloudBaseInstance, options: IMySqlOptions) {
  const cloudbaseFetch = cloudbase.request.fetch.bind(cloudbase.request)
  const { instance = 'default', database = cloudbase.config.env } = options || {}
  const fetch = async (url: RequestInfo | URL, options: RequestInit) => {
    let headers = {}
    if (options.headers instanceof Headers) {
      options.headers.forEach((value, key) => {
        headers[key] = value
      })
    } else {
      headers = options.headers || {}
    }

    const result = await cloudbaseFetch({
      url: url.toString(),
      ...options,
      headers: {
        'Content-Type': 'application/json',
        'X-Db-Instance': instance,
        'Accept-Profile': database,
        'Content-Profile': database,
        ...headers,
      },
      shouldThrowOnError: false,
    })

    let data = {}
    try {
      data = await result.data
    } catch (e) {
      if (!e.message.includes('Unexpected end of JSON input')) {
        // 服务器会返回空字符串，导致解析失败，这时应当作正常处理
        throw e
      }
    }

    const res = {
      ok: result?.statusCode >= 200 && result?.statusCode < 300,
      status: result?.statusCode || 200,
      statusText: result?.statusMessage || 'OK',
      json: () => Promise.resolve(data || {}),
      text: () => Promise.resolve(typeof data === 'string' ? data : JSON.stringify(data || {})),
      headers: result?.header,
    }

    return res as Response
  }
  const { BASE_URL, PROTOCOL } = cloudbase.getEndPointWithKey('GATEWAY') as {
    BASE_URL: string
    PROTOCOL: string
  }
  const mysqlBaseUrl = `${PROTOCOL}${BASE_URL}/rdb/rest`

  const entity = generateMySQLClient(cloudbase, {
    mysqlBaseUrl,
    fetch,
  })

  return entity
}

const component: ICloudbaseComponent = {
  name: 'mysql',
  entity: {
    mysql(options: IMySqlOptions) {
      return getEntity(this, options)(options)
    },
  },
}
const rdbComponent: ICloudbaseComponent = {
  name: 'rdb',
  entity: {
    rdb(options: IMySqlOptions) {
      return getEntity(this, options)(options)
    },
  },
}

try {
  cloudbase.registerComponent(component)
  cloudbase.registerComponent(rdbComponent)
} catch (e) {}

export function registerMySQL(app: ICloudbase) {
  try {
    app.registerComponent(component)
    app.registerComponent(rdbComponent)
  } catch (e) {
    console.warn(e)
  }
}

try {
  (window as any).registerMySQL = registerMySQL
} catch (e) {}


export * from '@cloudbase/wx-cloud-client-sdk'
